"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ── Types ──────────────────────────────────────────────────────────────────

type StepperOrientation = "horizontal" | "vertical"
type StepperState = "active" | "completed" | "inactive"

// ── Contexts ───────────────────────────────────────────────────────────────

type StepperContextValue = {
  value: string
  onValueChange: (value: string) => void
  orientation: StepperOrientation
}

type StepperItemContextValue = {
  step: string
  state: StepperState
  disabled: boolean
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

// ── Hooks ──────────────────────────────────────────────────────────────────

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ── Stepper ────────────────────────────────────────────────────────────────

type StepperProps = React.ComponentProps<"div"> & {
  /** The controlled active step value. */
  value?: string
  /** The default active step when uncontrolled. */
  defaultValue?: string
  /** Called when the active step changes. */
  onValueChange?: (value: string) => void
  /** Visual layout direction. @default "horizontal" */
  orientation?: StepperOrientation
}

function Stepper({
  value: valueProp,
  defaultValue = "",
  onValueChange,
  orientation = "horizontal",
  className,
  ...props
}: StepperProps) {
  const [internalValue, setInternalValue] = React.useState(defaultValue)
  const isControlled = valueProp !== undefined
  const value = isControlled ? valueProp : internalValue

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (!isControlled) {
        setInternalValue(newValue)
      }
      onValueChange?.(newValue)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex",
          orientation === "horizontal" ? "flex-row items-start" : "flex-col",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ── StepperItem ────────────────────────────────────────────────────────────

type StepperItemProps = React.ComponentProps<"div"> & {
  /** Unique identifier for this step; matched against the Stepper's value. */
  step: string
  /** Mark this step as completed (shows check icon in indicator). */
  completed?: boolean
  /** Prevent interaction with this step. */
  disabled?: boolean
}

function StepperItem({
  step,
  completed = false,
  disabled = false,
  className,
  ...props
}: StepperItemProps) {
  const { value, orientation } = useStepper()

  const isActive = value === step
  const state: StepperState = isActive
    ? "active"
    : completed
      ? "completed"
      : "inactive"

  return (
    <StepperItemContext.Provider value={{ step, state, disabled }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-disabled={disabled ? "" : undefined}
        className={cn(
          "group/stepper-item flex shrink-0",
          orientation === "horizontal" ? "flex-col items-center" : "flex-col",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ── StepperTrigger ─────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  onClick,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange, orientation } = useStepper()
  const { step, state, disabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={state}
      disabled={disabled}
      onClick={(e) => {
        onValueChange(step)
        onClick?.(e)
      }}
      className={cn(
        "flex items-start gap-3 rounded-md outline-none transition-all",
        "focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        orientation === "horizontal" && "flex-col items-center gap-1.5",
        className
      )}
      {...props}
    />
  )
}

// ── StepperIndicator ───────────────────────────────────────────────────────

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"span">) {
  const { state } = useStepperItem()

  return (
    <span
      data-slot="stepper-indicator"
      data-state={state}
      className={cn(
        "flex size-8 shrink-0 select-none items-center justify-center rounded-full border-2 text-xs font-semibold transition-colors",
        state === "completed" &&
          "border-primary bg-primary text-primary-foreground",
        state === "active" && "border-primary bg-background text-primary",
        state === "inactive" &&
          "border-border bg-background text-muted-foreground",
        className
      )}
      {...props}
    >
      {state === "completed" ? (
        <CheckIcon className="size-4" aria-hidden />
      ) : (
        children
      )}
    </span>
  )
}

// ── StepperTitle ───────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-medium leading-none",
        state === "inactive" && "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ── StepperDescription ─────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ── StepperSeparator ───────────────────────────────────────────────────────

type StepperSeparatorProps = React.ComponentProps<"div"> & {
  /**
   * Explicitly mark this separator as completed (renders in primary colour).
   * When omitted and the separator is nested inside a `StepperItem`, the
   * item's own state is used automatically.
   */
  completed?: boolean
}

function StepperSeparator({
  className,
  completed,
  ...props
}: StepperSeparatorProps) {
  // Gracefully consume both contexts; separator may sit between items or
  // inside one (either placement is valid).
  const stepperCtx = React.useContext(StepperContext)
  const itemCtx = React.useContext(StepperItemContext)

  const orientation = stepperCtx?.orientation ?? "horizontal"
  const isCompleted =
    completed !== undefined ? completed : itemCtx?.state === "completed"

  return (
    <div
      role="none"
      data-slot="stepper-separator"
      data-orientation={orientation}
      data-state={isCompleted ? "completed" : "inactive"}
      className={cn(
        "shrink-0 rounded-full bg-border transition-colors",
        isCompleted && "bg-primary",
        orientation === "horizontal"
          ? // mt-[15px] centres the 2px bar on the size-8 (32px) indicator
            // (32px / 2 − 1px = 15px)
            "mt-[15px] h-[2px] flex-1 self-start"
          : // ms-[15px] centres the 2px bar on the size-8 (32px) indicator
            "ms-[15px] mt-1 min-h-6 w-[2px]",
        className
      )}
      {...props}
    />
  )
}

// ── StepperContent ─────────────────────────────────────────────────────────

/**
 * Panel that is only rendered when its parent `StepperItem` is active.
 * Designed primarily for vertical steppers; in horizontal layouts consider
 * rendering content outside the `Stepper` altogether.
 */
function StepperContent({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { state } = useStepperItem()

  if (state !== "active") return null

  return (
    <div
      data-slot="stepper-content"
      data-state={state}
      className={cn("text-sm", className)}
      {...props}
    />
  )
}

// ── Exports ────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
  useStepperItem,
}

"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperIndicator,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

// ── Shared step data ───────────────────────────────────────────────────────

const WIZARD_STEPS = [
  {
    step: "1",
    title: "Account",
    description: "Your details",
    content:
      "Provide your name and email address so we can set up your account.",
  },
  {
    step: "2",
    title: "Profile",
    description: "Personalize",
    content:
      "Upload a profile photo and write a short bio to help others know you.",
  },
  {
    step: "3",
    title: "Review",
    description: "Confirm",
    content:
      "Check everything looks right, then click Finish to complete setup.",
  },
]

const ONBOARDING_STEPS = [
  {
    step: "welcome",
    title: "Welcome",
    description: "Get started",
    content: "Thanks for joining! Let's walk you through the key features.",
  },
  {
    step: "connect",
    title: "Connect",
    description: "Link accounts",
    content:
      "Connect your existing tools and services for a seamless experience.",
  },
  {
    step: "done",
    title: "All set",
    description: "You're ready",
    content: "Your workspace is configured. Start exploring your dashboard.",
  },
]

// ── Horizontal wizard ──────────────────────────────────────────────────────

function HorizontalStepper() {
  const [active, setActive] = React.useState("1")

  const index = WIZARD_STEPS.findIndex((s) => s.step === active)
  const isFirst = index === 0
  const isLast = index === WIZARD_STEPS.length - 1

  function go(offset: number) {
    const next = WIZARD_STEPS[index + offset]
    if (next) setActive(next.step)
  }

  return (
    <div className="flex w-full flex-col gap-6">
      <Stepper value={active} onValueChange={setActive}>
        {WIZARD_STEPS.map((s, i) => (
          <React.Fragment key={s.step}>
            <StepperItem
              step={s.step}
              completed={parseInt(s.step) < parseInt(active)}
            >
              <StepperTrigger>
                <StepperIndicator>{s.step}</StepperIndicator>
                <div className="hidden text-center sm:block">
                  <StepperTitle>{s.title}</StepperTitle>
                  <StepperDescription>{s.description}</StepperDescription>
                </div>
              </StepperTrigger>
            </StepperItem>
            {i < WIZARD_STEPS.length - 1 && (
              <StepperSeparator completed={parseInt(active) > i + 1} />
            )}
          </React.Fragment>
        ))}
      </Stepper>

      <div className="min-h-20 rounded-lg border p-4 text-sm text-muted-foreground">
        {WIZARD_STEPS[index]?.content}
      </div>

      <div className="flex items-center justify-between">
        <Button
          variant="outline"
          size="sm"
          disabled={isFirst}
          onClick={() => go(-1)}
        >
          Back
        </Button>
        <Button size="sm" disabled={isLast} onClick={() => go(1)}>
          {isLast ? "Finish" : "Next"}
        </Button>
      </div>
    </div>
  )
}

// ── Vertical onboarding ────────────────────────────────────────────────────

function VerticalStepper() {
  const [active, setActive] = React.useState("welcome")

  return (
    <Stepper
      value={active}
      onValueChange={setActive}
      orientation="vertical"
      className="w-full"
    >
      {ONBOARDING_STEPS.map((s, i) => (
        <React.Fragment key={s.step}>
          <StepperItem
            step={s.step}
            completed={
              ONBOARDING_STEPS.findIndex((x) => x.step === active) >
              ONBOARDING_STEPS.findIndex((x) => x.step === s.step)
            }
          >
            <StepperTrigger>
              <StepperIndicator>{i + 1}</StepperIndicator>
              <div>
                <StepperTitle>{s.title}</StepperTitle>
                <StepperDescription>{s.description}</StepperDescription>
              </div>
            </StepperTrigger>
            <StepperContent className="ms-11 pb-2 text-muted-foreground">
              {s.content}
            </StepperContent>
          </StepperItem>
          {i < ONBOARDING_STEPS.length - 1 && (
            <StepperSeparator
              completed={
                ONBOARDING_STEPS.findIndex((x) => x.step === active) > i
              }
            />
          )}
        </React.Fragment>
      ))}
    </Stepper>
  )
}

// ── Demo ───────────────────────────────────────────────────────────────────

export default function StepperDemo() {
  return (
    <div className="flex w-full max-w-xl flex-col gap-12">
      {/* Horizontal */}
      <div className="flex flex-col gap-3">
        <p className="text-xs font-medium text-muted-foreground uppercase tracking-wide">
          Horizontal
        </p>
        <HorizontalStepper />
      </div>

      {/* Vertical */}
      <div className="flex flex-col gap-3">
        <p className="text-xs font-medium text-muted-foreground uppercase tracking-wide">
          Vertical
        </p>
        <VerticalStepper />
      </div>
    </div>
  )
}
